#include <stdio.h>
#include <stdlib.h>
int main(){
    int T; if(scanf("%d",&T)!=1) return 0;
    while(T--){
        int N,K; scanf("%d %d",&N,&K);
        long long *a = (long long*)malloc(N*sizeof(long long));
        for(int i=0;i<N;++i) scanf("%lld",&a[i]);
        long long cur=0;
        for(int i=0;i<K;++i) cur+=a[i];
        long long best=cur;
        for(int i=K;i<N;++i){
            cur+=a[i]-a[i-K];
            if(cur<best) best=cur;
        }
        printf("%lld\n",best);
        free(a);
    }
    return 0;
}

